package com.wjx871.population.keypopulation;import com.wjx871.population.application.*;import com.wjx871.population.security.SensitiveDataMaskingService;import java.time.*;import java.util.List;
record KeyPopulationView(Long recordId,Long personId,String personName,String idCard,String phone,String address,String regionCode,String populationType,AttentionLevel attentionLevel,String registerReason,LocalDate registerDate,Long responsibleDepartmentId,Long responsibleUserId,KeyPopulationStatus status,String releaseReason,LocalDate releaseDate,Long sourceApplicationId,Integer version,LocalDateTime createdAt,LocalDateTime updatedAt){static KeyPopulationView from(KeyPopulationRecord x,SensitiveDataMaskingService m){return new KeyPopulationView(x.getRecordId(),x.getPersonId(),x.getPersonName(),m.identity(x.getIdCard()),m.phone(x.getPhone()),m.address(x.getAddress()),x.getRegionCode(),x.getPopulationType(),x.getAttentionLevel(),x.getRegisterReason(),x.getRegisterDate(),x.getResponsibleDepartmentId(),x.getResponsibleUserId(),x.getStatus(),x.getReleaseReason(),x.getReleaseDate(),x.getSourceApplicationId(),x.getVersion(),x.getCreatedAt(),x.getUpdatedAt());}}
record KeyApplicationView(ApplicationView application,Long detailId,KeyOperationType operationType,Long recordId,Long personId,String populationType,AttentionLevel attentionLevel,String reason,LocalDate eventDate,Long responsibleDepartmentId,Long responsibleUserId,KeyApplicationStatus businessStatus,Integer version,boolean executable){static KeyApplicationView from(BusinessApplication a,KeyPopulationApplication d){return new KeyApplicationView(ApplicationView.from(a),d.getDetailId(),d.getOperationType(),d.getRecordId(),d.getPersonId(),d.getPopulationType(),d.getAttentionLevel(),d.getReason(),d.getEventDate(),d.getResponsibleDepartmentId(),d.getResponsibleUserId(),d.getBusinessStatus(),d.getVersion(),a.getStatus()==ApplicationStatus.APPROVED&&d.getBusinessStatus()==KeyApplicationStatus.APPROVED);}}
record KeyPopulationDetailView(KeyApplicationView application,List<com.wjx871.population.material.MaterialView> materials,List<com.wjx871.population.approval.ApprovalLogView> approvalLogs){}
